    constexpr uint16_t make_dtau_entry(int ccc)
    {
        // ((((ccc*ccc)/4) * 43) / 128) + 60
        int t = ccc * ccc; // up to 4096 for ccc<=64
        t = t / 4;         // integer divide
        t = t * 43;
        t = t / 128;
        t = t + 60;
        if (t < 0) t = 0;
        if (t > 0xFFFF) t = 0xFFFF;
        return (uint16_t)t;
    }

